import pymongo
from pymongo import MongoClient
from pymongo.errors import OperationFailure
import json

def connect_to_mongodb(host='localhost', port=27017, db_name='mydatabase', collection_name='mycollection'):
    """Establishes connection to MongoDB and returns the collection object."""
    try:
        client = MongoClient(host, port)
        db = client[db_name]
        collection = db[collection_name]
        print(f"Successfully connected to MongoDB: {host}:{port}/{db_name}/{collection_name}")
        return collection
    except Exception as e:
        print(f"Error connecting to MongoDB: {e}")
        return None

def seed_data(collection):
    """Seeds some sample data into the collection if it's empty."""
    if collection.count_documents({}) == 0:
        sample_data = [
            {"item": "laptop", "qty": 50, "tags": ["electronics", "office"], "price": 1200},
            {"item": "mouse", "qty": 120, "tags": ["electronics", "peripheral"], "price": 25},
            {"item": "keyboard", "qty": 80, "tags": ["electronics", "peripheral"], "price": 75},
            {"item": "monitor", "qty": 30, "tags": ["electronics", "display"], "price": 300},
            {"item": "desk", "qty": 10, "tags": ["furniture", "office"], "price": 450},
            {"item": "chair", "qty": 20, "tags": ["furniture", "office"], "price": 150},
            {"item": "headphones", "qty": 70, "tags": ["audio", "electronics"], "price": 100},
            {"item": "webcam", "qty": 40, "tags": ["electronics", "peripheral"], "price": 50}
        ]
        collection.insert_many(sample_data)
        print("Seeded sample data.")
    else:
        print("Collection already contains data. Skipping seeding.")

def find_documents_with_javascript_filter(collection, js_expression):
    """
    Performs a MongoDB query using the $where operator with a server-side JavaScript expression.
    """
    print(f"\nExecuting query with $where: {js_expression}")
    try:
        # Construct the query using $where operator
        query = {"$where": js_expression}
        
        # Execute the query
        results = list(collection.find(query))
        
        if results:
            print("Found documents:")
            for doc in results:
                print(json.dumps(doc, indent=2))
        else:
            print("No documents matched the filter.")
        return results
    except OperationFailure as e:
        print(f"MongoDB Operation Error: {e}")
        print("Ensure your JavaScript expression is valid and does not have syntax errors.")
        print("Also check for potential server-side resource limitations or security restrictions.")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    return []

def main():
    collection = connect_to_mongodb()
    if collection is None:
        return

    seed_data(collection)

    print("\n--- Advanced Data Filtering Service ---")
    print("Enter JavaScript expressions to filter documents.")
    print("Examples:")
    print("  this.qty > 50 && this.price < 200")
    print("  this.tags.includes('electronics') && this.qty < 100")
    print("  this.item.startsWith('m') && this.price < 100")
    print("  this.qty * this.price > 10000")
    print("  function() { return this.qty > 50; }") # Using a function wrapper
    print("Type 'exit' or 'quit' to stop.")

    while True:
        user_input = input("\nEnter JavaScript filter expression: ")
        if user_input.lower() in ['exit', 'quit']:
            break
        
        if not user_input.strip():
            print("Expression cannot be empty. Please provide a valid JavaScript expression.")
            continue

        find_documents_with_javascript_filter(collection, user_input)

    print("\nExiting Advanced Data Filtering Service. Goodbye!")

if __name__ == "__main__":
    main()